import{N as e,h as t,k as n,p as r,u as i}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as a}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const o=JSON.parse(`{"title":"Міграція мапінгів","description":"Дізнайтеся, як мігрувати обфусковані мапінги вашого мода.","frontmatter":{"title":"Міграція мапінгів","description":"Дізнайтеся, як мігрувати обфусковані мапінги вашого мода.","authors":["ArduFish","asiekierka","cassiancc","Daomephsta","deirn","Earthcomputer","florensie","Friendly-Banana","IMB11","jamierocks","JamiesWhiteShirt","liach","MildestToucan","modmuss50","natanfudge","Spinoscythe","UpcraftLP"],"authors-nogithub":["basil4088"],"resources":{"https://www.minecraft.net/en-us/article/removing-obfuscation-in-java-edition":"Видалення обфускації Java Edition — Minecraft.net","https://fabricmc.net/2025/10/31/obfuscation.html":"Видалення обфускації з Fabric","../../404":"Данина Fabric Yarn (2016-2025)"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/porting/mappings/index.md","filePath":"translated/uk_ua/develop/porting/mappings/index.md","lastUpdated":1774518827000}`);var s={name:`uk_ua/develop/porting/mappings/index.md`};function c(a,o,s,c,l,u){let d=e(`ChoiceComponent`);return n(),i(`div`,null,[o[0]||=r(`<h1 id="h1" tabindex="-1">Міграція мапінгів <a class="header-anchor" href="#h1" aria-label="Permalink to “Міграція мапінгів”">​</a></h1><p>Можливо, ви захочете перейти з Yarn на мапінги Mojang, особливо якщо ви плануєте <a href="#whats-going-on-with-mappings">оновити свій мод після покращення</a> Mounts of Mayhem.</p><p>Є два способи зробити це: ви можете використовувати <strong>плаґін Loom Gradle</strong> або <strong>плаґін Ravel IntelliJ IDEA</strong>.</p><p>Loom пропонує напівавтоматичне переміщення мапінгів за допомогою завдання <code>migrateMappings</code>, але <strong>не підтримує перенесення коду, написаного на Kotlin</strong>.</p><p>Ravel — це плаґін для IntelliJ IDEA, який додає діалог інтерфейсу для міграції. Однак, на відміну від Loom, Ravel також <strong>підтримує Kotlin</strong>. Крім того, Ravel може працювати краще, ніж Loom, для складніших проєктів, оскільки він використовує IDE для вирішення змін.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Fabric API використовує Ravel для переходу з мапінгів Yarn на Mojang. Перегляньте <a href="https://github.com/FabricMC/fabric/pull/4960" target="_blank" rel="noreferrer">PR #4690 в репозиторії API Fabric</a>.</p></div><p>Жоден варіант не є ідеальним, і вам все одно доведеться переглядати результати та вносити виправлення вручну, особливо якщо ви переміщуєте міксини.</p>`,7),t(d,{choices:[{name:`Loom Gradle Plugin`,href:`./loom`,icon:`simple-icons:gradle`,color:`#4DC9C0`},{name:`Ravel IntelliJ IDEA Plugin`,href:`./ravel`,icon:`simple-icons:intellijidea`,color:`#FE2857`}]}),o[1]||=r(`<h2 id="whats-going-on-with-mappings" tabindex="-1">Що відбувається з мапінгами? <a class="header-anchor" href="#whats-going-on-with-mappings" aria-label="Permalink to “Що відбувається з мапінгами?”">​</a></h2><p>Історично Minecraft: Java Edition використовував обфускацію, що призвело до розробки мап обфускації, які Fabric Loom використовує для модифікації. Було два варіанти: або власні мапінги Yarn від Fabric, або офіційні мапінги Mojang.</p><p>Mojang нещодавно оголосили, що <a href="https://www.minecraft.net/en-us/article/removing-obfuscation-in-java-edition" target="_blank" rel="noreferrer">вони видаляють обфускацію коду з Minecraft: Java Edition</a>, а Fabric Project розробив <a href="https://fabricmc.net/2025/10/31/obfuscation.html" target="_blank" rel="noreferrer">свій план роботи з цією зміною</a>. Якщо ви плануєте оновити свій мод до цієї версії, вам потрібно буде спочатку перейти до маппінгів обфускації Mojang перед оновленням.</p><h2 id="mappings" tabindex="-1">Що таке мапінги? <a class="header-anchor" href="#mappings" aria-label="Permalink to “Що таке мапінги?”">​</a></h2><p>Minecraft: Java Edition було обфусковано з моменту його випуску, що означає, що його код мав зручні для людини назви класів, як-от <code>Creeper</code>, замінені на тарабарщину, як-от <code>brc</code>. Щоб легко модифікувати його, Fabric Loom використовує мапи обфускації: посилання, які перетворюють заплутані назви класів, як-от <code>brc</code>, назад у зручні для людини назви, такі як <code>CreeperEntity</code>.</p><p>Як розробник Fabric ви зіткнетеся з трьома основними наборами імен:</p><ul><li><strong>Intermediary</strong>: набір мапінгів, який використовується скомпільованими модами Fabric; наприклад <code>brc</code> може стати <code>class_1548</code>. Суть Intermediary полягає в тому, що він пропонує стабільний набір імен у всіх випусках, оскільки обфусковані імена класів змінюються з кожною новою версією Minecraft. Це часто дозволяє модам, створеним для однієї версії, працювати на інших, якщо уражені частини гри не сильно змінилися.</li><li><strong>Yarn</strong>: набір мап із відкритим кодом, розроблений Fabric для написання модів людьми. Більшість модів Fabric використовували мапінги Yarn, оскільки вони були типовими до 2025 року. Прикладом мапінгу може бути <code>CreeperEntity</code>.</li><li><strong>Мапінги Mojang</strong>: офіційні мапінги обфускації гри, випущені Mojang у 2019 році для допомоги в розробці модів. Примітно, що у мапінгах обфускації Mojang відсутні назви параметрів і Javadocs, тому деякі користувачі також накладають <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> на офіційні мапінги. Прикладом мапінгу може бути <code>Creeper</code>.</li></ul><p>Minecraft 26.1 буде деобфускатованим та включатиме назви параметрів, тому не буде потреби в будь-яких мапінгах обфускації.</p>`,8)])}var l=a(s,[[`render`,c]]);export{o as __pageData,l as default};